// frontend/src/pages/Events.js
import { useEffect, useMemo, useState } from "react";
import api from "../api";
import { useAuth } from "../AuthContext";
import { toast } from "react-toastify";

/** ====== Helpers ====== **/
const PAGE_SIZE = 10;

const TYPE_OPTS = [
    { label: "Gặp khách hàng", value: "MEETING" },
    { label: "Nhắc thanh toán", value: "PAYMENT_REMINDER" },
    { label: "Gia hạn HĐ", value: "CONTRACT_RENEWAL" },
    { label: "Khác", value: "OTHER" },
];

const STATUS_OPTS = [
    { label: "Đã lên lịch", value: "SCHEDULED" },
    { label: "Hoàn thành", value: "DONE" },
    { label: "Huỷ", value: "CANCELED" },
];

const findLabel = (list, v) => list.find((x) => x.value === v)?.label || v || "-";

/** yyyy-MM-ddTHH:mm for <input type="datetime-local" /> */
function toLocalInput(v) {
    if (!v) return "";
    const d = typeof v === "string" ? new Date(v) : v;
    if (Number.isNaN(d.getTime())) return "";
    const yyyy = d.getFullYear();
    const mm = String(d.getMonth() + 1).padStart(2, "0");
    const dd = String(d.getDate()).padStart(2, "0");
    const hh = String(d.getHours()).padStart(2, "0");
    const mi = String(d.getMinutes()).padStart(2, "0");
    return `${yyyy}-${mm}-${dd}T${hh}:${mi}`;
}

function emptyForm() {
    return {
        id: null,
        title: "",
        type: "MEETING",
        description: "",
        customerId: "",
        contractId: "",
        assigneeUserId: "", // nếu để trống, BE sẽ gán người tạo
        startAt: toLocalInput(new Date()),
        endAt: "",
        status: "SCHEDULED",
        notifyByEmail: false,
        notifyInApp: true,
    };
}

export default function EventsPage() {
    const { user } = useAuth();

    const isAdmin = useMemo(
        () => (user?.roles || []).some((r) => String(r).toUpperCase().includes("ADMIN")),
        [user]
    );
    const isSales = useMemo(
        () => (user?.roles || []).some((r) => String(r).toUpperCase().includes("SALES")),
        [user]
    );
    const isAccountant = useMemo(
        () => (user?.roles || []).some((r) => String(r).toUpperCase().includes("ACCOUNTANT")),
        [user]
    );

    // View mode: SALES/ACCOUNTANT xem “của tôi” là mặc định; ADMIN/ACCOUNTANT có thể chuyển qua “Toàn hệ thống”
    const [adminView, setAdminView] = useState(isAdmin); // nếu là admin, mặc định mở system view
    const [rows, setRows] = useState([]);
    const [statusFilter, setStatusFilter] = useState("");
    const [page, setPage] = useState(0);
    const [pages, setPages] = useState(1);
    const [loading, setLoading] = useState(false);

    // Form
    const [showForm, setShowForm] = useState(false);
    const [form, setForm] = useState(emptyForm());
    const canEdit = isAdmin || isSales; // ACCOUNTANT chỉ xem

    // Dropdown customers/contracts
    const [customers, setCustomers] = useState([]);
    const [contracts, setContracts] = useState([]);

    useEffect(() => {
        loadEvents(0);
        // Tải options KH/HĐ (page nhỏ)
        loadCustomers();
        loadContracts();
        // eslint-disable-next-line
    }, [adminView, statusFilter]);

    async function loadEvents(p = 0) {
        try {
            setLoading(true);
            const params = { page: p, size: PAGE_SIZE };
            if (statusFilter) params.status = statusFilter;

            let url = "/api/events/me";
            if ((isAdmin || isAccountant) && adminView) url = "/api/events/admin";

            const res = await api.get(url, { params });
            const data = res.data;
            const list = Array.isArray(data?.content) ? data.content : Array.isArray(data) ? data : [];
            setRows(list);
            setPage(data?.number ?? p);
            setPages(data?.totalPages ?? 1);
        } catch (e) {
            console.error(e);
            toast.error("Tải danh sách sự kiện thất bại");
        } finally {
            setLoading(false);
        }
    }

    async function loadCustomers() {
        try {
            // ADMIN/SALES có quyền; ACCOUNTANT có thể 403 — ignore
            const res = await api.get("/api/customers", { params: { page: 0, size: 200 } });
            const data = res.data;
            const list = Array.isArray(data?.content) ? data.content : Array.isArray(data) ? data : [];
            setCustomers(list);
        } catch {}
    }

    async function loadContracts() {
        try {
            const res = await api.get("/api/contracts", { params: { page: 0, size: 200 } });
            const data = res.data;
            const list = Array.isArray(data?.content) ? data.content : Array.isArray(data) ? data : [];
            setContracts(list);
        } catch {}
    }

    function openCreate() {
        setForm(emptyForm());
        setShowForm(true);
    }

    function openEdit(row) {
        setForm({
            id: row.id,
            title: row.title || "",
            type: row.type || "MEETING",
            description: row.description || "",
            customerId: row.customerId || "",
            contractId: row.contractId || "",
            assigneeUserId: row.assigneeId || "",
            startAt: toLocalInput(row.startAt),
            endAt: toLocalInput(row.endAt),
            status: row.status || "SCHEDULED",
            notifyByEmail: !!row.notifyByEmail,
            notifyInApp: !!row.notifyInApp,
        });
        setShowForm(true);
    }

    async function onSave(e) {
        e.preventDefault();
        if (!canEdit) return;

        const payload = {
            title: form.title?.trim(),
            type: form.type,
            description: form.description || "",
            customerId: form.customerId || null,
            contractId: form.contractId || null,
            assigneeUserId: form.assigneeUserId || null,
            startAt: form.startAt ? new Date(form.startAt).toISOString() : null,
            endAt: form.endAt ? new Date(form.endAt).toISOString() : null,
            status: form.status,
            notifyByEmail: !!form.notifyByEmail,
            notifyInApp: !!form.notifyInApp,
        };

        try {
            if (form.id) {
                await api.put(`/api/events/${form.id}`, payload);
                toast.success("Cập nhật sự kiện thành công");
            } else {
                await api.post("/api/events", payload);
                toast.success("Tạo sự kiện thành công");
            }
            setShowForm(false);
            loadEvents(page);
        } catch (err) {
            console.error(err);
            toast.error("Lưu sự kiện thất bại");
        }
    }

    async function onDelete(row) {
        if (!canEdit) return;
        if (!window.confirm(`Xoá sự kiện "${row.title}"?`)) return;
        try {
            await api.delete(`/api/events/${row.id}`);
            toast.success("Đã xoá");
            // nếu còn 1 bản ghi cuối ở trang hiện tại, lùi về trang trước
            const nextPage = rows.length > 1 ? page : Math.max(0, page - 1);
            loadEvents(nextPage);
        } catch (e) {
            console.error(e);
            toast.error("Xoá sự kiện thất bại");
        }
    }

    return (
        <div className="p-4">
            <div className="mb-4 flex items-center justify-between gap-2">
                <h1 className="text-xl font-semibold">Sự kiện / Nhắc nhở</h1>
                <div className="flex items-center gap-2">
                    {(isAdmin || isAccountant) && (
                        <label className="text-sm flex items-center gap-1">
                            <input
                                type="checkbox"
                                checked={adminView}
                                onChange={(e) => setAdminView(e.target.checked)}
                            />
                            Xem toàn hệ thống
                        </label>
                    )}
                    <select
                        className="border rounded px-2 py-1 text-sm"
                        value={statusFilter}
                        onChange={(e) => setStatusFilter(e.target.value)}
                    >
                        <option value="">-- Tất cả trạng thái --</option>
                        {STATUS_OPTS.map((s) => (
                            <option key={s.value} value={s.value}>{s.label}</option>
                        ))}
                    </select>
                    {canEdit && (
                        <button className="bg-blue-600 text-white px-3 py-1 rounded" onClick={openCreate}>
                            + Tạo sự kiện
                        </button>
                    )}
                </div>
            </div>

            <div className="border rounded">
                <table className="w-full text-sm">
                    <thead className="bg-gray-50">
                    <tr>
                        <th className="text-left p-2">Tiêu đề</th>
                        <th className="text-left p-2">Loại</th>
                        <th className="text-left p-2">Khách hàng</th>
                        <th className="text-left p-2">Hợp đồng</th>
                        <th className="text-left p-2">Phụ trách</th>
                        <th className="text-left p-2">Bắt đầu</th>
                        <th className="text-left p-2">Kết thúc</th>
                        <th className="text-left p-2">Trạng thái</th>
                        <th className="text-right p-2">Thao tác</th>
                    </tr>
                    </thead>
                    <tbody>
                    {!loading && rows.length === 0 && (
                        <tr>
                            <td className="p-3 text-center text-gray-500" colSpan={9}>Không có sự kiện</td>
                        </tr>
                    )}
                    {rows.map((r) => (
                        <tr key={r.id} className="border-t">
                            <td className="p-2">{r.title}</td>
                            <td className="p-2">{findLabel(TYPE_OPTS, r.type)}</td>
                            <td className="p-2">{r.customerName || "-"}</td>
                            <td className="p-2">{r.contractCode || (r.contractId ?? "-")}</td>
                            <td className="p-2">{r.assigneeName || (r.assigneeId ?? "-")}</td>
                            <td className="p-2">{r.startAt ? new Date(r.startAt).toLocaleString() : "-"}</td>
                            <td className="p-2">{r.endAt ? new Date(r.endAt).toLocaleString() : "-"}</td>
                            <td className="p-2">{findLabel(STATUS_OPTS, r.status)}</td>
                            <td className="p-2">
                                <div className="flex justify-end gap-2">
                                    {canEdit && (
                                        <>
                                            <button className="px-2 py-1 border rounded" onClick={() => openEdit(r)}>
                                                Sửa
                                            </button>
                                            <button className="px-2 py-1 border rounded" onClick={() => onDelete(r)}>
                                                Xoá
                                            </button>
                                        </>
                                    )}
                                </div>
                            </td>
                        </tr>
                    ))}
                    {loading && (
                        <tr>
                            <td className="p-3 text-center text-gray-500" colSpan={9}>Đang tải…</td>
                        </tr>
                    )}
                    </tbody>
                </table>
            </div>

            {/* Pagination */}
            <div className="mt-3 flex items-center justify-between">
                <div className="text-sm text-gray-500">Trang {page + 1} / {pages}</div>
                <div className="flex gap-2">
                    <button className="px-3 py-1 border rounded" disabled={page <= 0} onClick={() => loadEvents(page - 1)}>Trước</button>
                    <button className="px-3 py-1 border rounded" disabled={page >= pages - 1} onClick={() => loadEvents(page + 1)}>Sau</button>
                </div>
            </div>

            {/* Modal Form */}
            {showForm && (
                <div className="fixed inset-0 bg-black/40 flex items-center justify-center z-50">
                    <form className="bg-white rounded-lg shadow-lg w-full max-w-2xl p-4" onSubmit={onSave}>
                        <div className="flex items-center justify-between mb-3">
                            <div className="text-lg font-semibold">{form.id ? "Sửa sự kiện" : "Tạo sự kiện"}</div>
                            <button type="button" className="text-gray-500" onClick={() => setShowForm(false)}>✕</button>
                        </div>

                        <div className="grid grid-cols-2 gap-3">
                            <div>
                                <label className="text-sm">Tiêu đề</label>
                                <input className="w-full border rounded px-2 py-1"
                                       value={form.title} onChange={(e) => setForm({ ...form, title: e.target.value })} required />
                            </div>
                            <div>
                                <label className="text-sm">Loại</label>
                                <select className="w-full border rounded px-2 py-1"
                                        value={form.type} onChange={(e) => setForm({ ...form, type: e.target.value })}>
                                    {TYPE_OPTS.map(o => <option key={o.value} value={o.value}>{o.label}</option>)}
                                </select>
                            </div>

                            <div>
                                <label className="text-sm">Khách hàng</label>
                                <select className="w-full border rounded px-2 py-1"
                                        value={form.customerId} onChange={(e) => setForm({ ...form, customerId: e.target.value })}>
                                    <option value="">-- Không --</option>
                                    {customers.map(c => <option key={c.id} value={c.id}>{c.name || c.fullName || `#${c.id}`}</option>)}
                                </select>
                            </div>
                            <div>
                                <label className="text-sm">Hợp đồng</label>
                                <select className="w-full border rounded px-2 py-1"
                                        value={form.contractId} onChange={(e) => setForm({ ...form, contractId: e.target.value })}>
                                    <option value="">-- Không --</option>
                                    {contracts.map(ct => <option key={ct.id} value={ct.id}>{ct.code || ct.contractCode || `#${ct.id}`}</option>)}
                                </select>
                            </div>

                            <div>
                                <label className="text-sm">Bắt đầu</label>
                                <input type="datetime-local" className="w-full border rounded px-2 py-1"
                                       value={form.startAt} onChange={(e) => setForm({ ...form, startAt: e.target.value })} />
                            </div>
                            <div>
                                <label className="text-sm">Kết thúc</label>
                                <input type="datetime-local" className="w-full border rounded px-2 py-1"
                                       value={form.endAt} onChange={(e) => setForm({ ...form, endAt: e.target.value })} />
                            </div>

                            <div>
                                <label className="text-sm">Trạng thái</label>
                                <select className="w-full border rounded px-2 py-1"
                                        value={form.status} onChange={(e) => setForm({ ...form, status: e.target.value })}>
                                    {STATUS_OPTS.map(s => <option key={s.value} value={s.value}>{s.label}</option>)}
                                </select>
                            </div>
                            <div className="flex items-center gap-3">
                                <label className="text-sm flex items-center gap-1">
                                    <input type="checkbox" checked={form.notifyByEmail}
                                           onChange={(e) => setForm({ ...form, notifyByEmail: e.target.checked })}/>
                                    Gửi email
                                </label>
                                <label className="text-sm flex items-center gap-1">
                                    <input type="checkbox" checked={form.notifyInApp}
                                           onChange={(e) => setForm({ ...form, notifyInApp: e.target.checked })}/>
                                    Thông báo trong app
                                </label>
                            </div>

                            <div className="col-span-2">
                                <label className="text-sm">Mô tả</label>
                                <textarea rows={3} className="w-full border rounded px-2 py-1"
                                          value={form.description} onChange={(e) => setForm({ ...form, description: e.target.value })}/>
                            </div>
                        </div>

                        <div className="mt-4 flex justify-end gap-2">
                            <button type="button" className="px-3 py-1 border rounded" onClick={() => setShowForm(false)}>Huỷ</button>
                            {canEdit && <button type="submit" className="px-3 py-1 bg-blue-600 text-white rounded">Lưu</button>}
                        </div>
                    </form>
                </div>
            )}
        </div>
    );
}
